#include <bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e6 + 10;
const int INF = 2e18;
int a[N], tag[4 * N], tag2[4 * N]; 

struct Info {
    int x;
    Info operator+ (const Info &o) const {
        return {max(x, o.x)};
    }
} d[4 * N];

inline void push_up(int x) {
    d[x] = d[x * 2] + d[x * 2 + 1];
}

void push_down(int x) {
    int l = x * 2, r = x * 2 + 1;
    if (tag2[x] != INF) {
        d[l].x = tag2[x];
        d[r].x = tag2[x];
        tag2[l] = tag2[x];
        tag2[r] = tag2[x];
        tag[l] = 0; 
        tag[r] = 0;
        tag2[x] = INF; 
    }
    if (tag[x] != 0) {
        d[l].x += tag[x];
        d[r].x += tag[x];
        tag[l] += tag[x];
        tag[r] += tag[x];
        tag[x] = 0; 
    }
}

void build(int x, int l, int r) {
    tag[x] = 0;
    tag2[x] = INF; 
    if (l == r) {
        d[x] = {a[l]};
        return;
    }
    int mid = (l + r) >> 1;
    build(x * 2, l, mid);
    build(x * 2 + 1, mid + 1, r);
    push_up(x);
}

void update1(int x, int l, int r, int a, int b, int v) { 
    if (a <= l && r <= b) {
        d[x].x += v; 
        tag[x] += v;
        return;
    }
    push_down(x); 
    int mid = (l + r) >> 1;
    if (a <= mid) 
        update1(x * 2, l, mid, a, b, v);
    if (b > mid) 
        update1(x * 2 + 1, mid + 1, r, a, b, v);
    push_up(x);
}

void update2(int x, int l, int r, int a, int b, int v) {
    if (a <= l && r <= b) {
        d[x].x = v;
        tag2[x] = v;
        tag[x] = 0; 
        return;
    }
    push_down(x); 
    int mid = (l + r) >> 1;
    if (a <= mid) 
        update2(x * 2, l, mid, a, b, v);
    if (b > mid) 
        update2(x * 2 + 1, mid + 1, r, a, b, v);
    push_up(x);
}

Info query(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) 
        return d[x];
    push_down(x);
    int mid = (l + r) >> 1;
    Info res = {-INF}; 
    if (a <= mid)
        res = res + query(x * 2, l, mid, a, b);
    if (b > mid) 
        res = res + query(x * 2 + 1, mid + 1, r, a, b);
    return res;
}

signed main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, q;
    cin >> n >> q;
    for (int i = 1; i <= n; i++) 
        cin >> a[i];
    build(1, 1, n);
    while (q--) {
        int op, x, y;
        cin >> op >> x >> y;
        if (op == 1) {
            int k;
            cin >> k;
            update2(1, 1, n, x, y, k);
        } 
        else if (op == 2) {
            int k;
            cin >> k;
            update1(1, 1, n, x, y, k);
        } 
        else {
            cout << query(1, 1, n, x, y).x << '\n';
        }
    }
    return 0;
}
